INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (680147223, 'officer_flavor_text_79', '<color=#40CFFF>CLASS:</color> ENGINEERING
<color=#40CFFF>GROUP:</color> GLORY IN THE KILL
<color=#40CFFF>FACTION:</color> KLINGON EMPIRE

Komal is unusual among Klingons in that he actually prefers to be an engineer. He puts up a proper front when around his fellows, but in his heart of hearts, he''d rather be wrenching than fighting. He''s found success on Klaa''s crew, as Klaa''s competitive nature and Kras''s measured attitude have worked in tandem to allow Komal to spend his efforts on engineering.', '2025-08-13 17:11:38');
INSERT INTO officer_translations (officer_id, key, text, modified) VALUES (680147223, 'officer_name_79', 'Komal', '2025-08-13 17:11:38');
